Paste this code into backend/server.js:

```js
const express = require('express');
const cors = require('cors');
const app = express();
app.use(cors());
app.use(express.json());

let users = [
  { id: 1, username: 'Alice', inventory: [{ id: 1, name: 'Golden Unicorn', value: 100 }] },
  { id: 2, username: 'Bob', inventory: [{ id: 2, name: 'Shadow Dragon', value: 100 }] }
];
let games = [];

app.get('/api/users', (req, res) => res.json(users));
app.get('/api/games', (req, res) => res.json(games));

app.post('/api/games', (req, res) => {
  const { creatorId, itemIds } = req.body;
  const creator = users.find(u => u.id === creatorId);
  const items = creator.inventory.filter(i => itemIds.includes(i.id));
  creator.inventory = creator.inventory.filter(i => !itemIds.includes(i.id));
  const game = { id: Date.now(), creatorId, creatorItems: items, status: 'waiting', joinerId: null, joinerItems: [] };
  games.push(game);
  res.json(game);
});

app.post('/api/games/:id/join', (req, res) => {
  const game = games.find(g => g.id == req.params.id);
  const { joinerId, itemIds } = req.body;
  const joiner = users.find(u => u.id === joinerId);
  const items = joiner.inventory.filter(i => itemIds.includes(i.id));
  joiner.inventory = joiner.inventory.filter(i => !itemIds.includes(i.id));
  game.joinerId = joinerId;
  game.joinerItems = items;
  game.status = 'in-progress';
  res.json(game);
});

app.post('/api/games/:id/resolve', (req, res) => {
  const game = games.find(g => g.id == req.params.id);
  const winner = Math.random() < 0.5 ? game.creatorId : game.joinerId;
  const winnerUser = users.find(u => u.id === winner);
  winnerUser.inventory.push(...game.creatorItems, ...game.joinerItems);
  game.status = 'finished';
  game.winner = winner;
  res.json({ winner, game });
});

app.listen(3001, () => console.log('Server running on http://localhost:3001'));
```

