import React, { useEffect, useState } from 'react';

const API = 'http://localhost:3001/api';

function App() {
  const [users, setUsers] = useState([]);
  const [games, setGames] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [selectedItems, setSelectedItems] = useState([]);
  const [refresh, setRefresh] = useState(false);

  useEffect(() => {
    fetch(`${API}/users`).then(res => res.json()).then(setUsers);
    fetch(`${API}/games`).then(res => res.json()).then(setGames);
  }, [refresh]);

  const selectUser = (user) => {
    setSelectedUser(user);
    setSelectedItems([]);
  };

  const toggleItem = (itemId) => {
    setSelectedItems((prev) =>
      prev.includes(itemId) ? prev.filter(id => id !== itemId) : [...prev, itemId]
    );
  };

  const createGame = async () => {
    await fetch(`${API}/games`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ creatorId: selectedUser.id, itemIds: selectedItems }),
    });
    setSelectedItems([]);
    setRefresh(r => !r);
  };

  const joinGame = async (game) => {
    // Find items in user's inventory that match the value
    const value = game.creatorItems.reduce((sum, i) => sum + i.value, 0);
    let sum = 0, joinItems = [];
    for (let item of selectedUser.inventory) {
      if (sum + item.value <= value) {
        joinItems.push(item.id);
        sum += item.value;
        if (sum === value) break;
      }
    }
    if (sum !== value) {
      alert('You do not have items matching the value!');
      return;
    }
    await fetch(`${API}/games/${game.id}/join`, {
